                <button 
                    className="create-user-btn"
                    onClick={() => setShowCreateUserForm(true)}
                >
                    ➕ Create New User
                </button>
            </div>

            {showCreateUserForm && (
                <div className="create-user-modal">
                    <div className="modal-content">
                        <h3>Create New User</h3>
                        <form onSubmit={handleCreateUser}>
                            <div className="form-row">
                                <input
                                    type="text"
                                    placeholder="First Name"
                                    value={newUserData.firstName}
                                    onChange={(e) => setNewUserData({...newUserData, firstName: e.target.value})}
                                    required
                                />
                                <input
                                    type="text"
                                    placeholder="Last Name"
                                    value={newUserData.lastName}
                                    onChange={(e) => setNewUserData({...newUserData, lastName: e.target.value})}
                                    required
                                />
                            </div>
                            <input
                                type="email"
                                placeholder="Email"
                                value={newUserData.email}
                                onChange={(e) => setNewUserData({...newUserData, email: e.target.value})}
                                required
                            />
                            <input
                                type="password"
                                placeholder="Password"
                                value={newUserData.password}
                                onChange={(e) => setNewUserData({...newUserData, password: e.target.value})}
                                required
                            />
                            <select
                                value={newUserData.role}
                                onChange={(e) => setNewUserData({...newUserData, role: e.target.value})}
                            >
                                <option value="student">Student</option>
                                <option value="teacher">Teacher</option>
                                <option value="admin">Admin</option>
                            </select>
                            <div className="form-actions">
                                <button type="submit">Create User</button>
                                <button type="button" onClick={() => setShowCreateUserForm(false)}>Cancel</button>
                            </div>
                        </form>
                    </div>
                </div>
            )}

            <div className="users-grid">
                {allUsers.map(user => (
                    <div key={user._id} className="user-card">
                        <div className="user-avatar">
                            {user.firstName?.charAt(0)}{user.lastName?.charAt(0)}
                        </div>
                        <div className="user-info">
                            <h4>{user.firstName} {user.lastName}</h4>
                            <p>{user.email}</p>
                            <span className={`role-badge ${user.role}`}>{user.role}</span>
                            <span className={`status-badge ${user.isApproved ? 'approved' : 'pending'}`}>
                                {user.isApproved ? '✅ Approved' : '⏳ Pending'}
                            </span>
                        </div>
                        {!user.isApproved && (
                            <div className="user-actions">
                                <button 
                                    className="approve-btn"
                                    onClick={() => handleUserApproval(user._id, true)}
                                >
                                    Approve
                                </button>
                                <button 
                                    className="reject-btn"
                                    onClick={() => handleUserApproval(user._id, false)}
                                >
                                    Reject
                                </button>
                            </div>
                        )}
                    </div>
                ))}
            </div>
        </div>
    );

